INSERT INTO `settings` (`id`, `key`, `display_name`, `value`, `details`, `type`, `order`, `group`, `created_at`, `updated_at`) VALUES (12, 'hod.message_body', 'Hod Message Body', 'The department is committed to academic excellence and innovation, preparing students to meet the technological challenges of the modern world. Our program is accredited by the Pakistan Engineering Council (PEC) and follows the Higher Education Commission (HEC)–approved curriculum, ensuring the highest academic standards and professional relevance. The department is proud to have a team of highly qualified, dedicated, and experienced faculty members who are passionate about teaching and mentorship. We provide our students with access to state-of-the-art laboratories, modern computational facilities, and a learning environment that fosters creativity, critical thinking, and professional growth.', '', 'text', 1, 'Hod', NULL, NULL);
