INSERT INTO `teachers` (`id`, `name`, `designation`, `photo`, `sort_order`, `qualifications`, `description`, `current_positions`, `education`, `experience`, `publications`, `awards`, `email`, `contact_number`, `code`, `department`, `created_at`, `updated_at`, `category`) VALUES (21, 'Engr. Aijaz Akhtar Memon', 'Assistant Professor', 'teachers/engr_aijaz_akhtar_memon.jpg', 4, 'M.E, B.E', '<p><span style="color: #666666; font-family: Arial, Helvetica, sans-serif;">B.E (MUET), M.E (Thailand)</span><br style="box-sizing: border-box; color: #666666; font-family: Arial, Helvetica, sans-serif; outline: none !important;" /><span style="color: #666666; font-family: Arial, Helvetica, sans-serif;">Assistant Professor</span></p>', '', '', '', '', '', 'aijaz.akhtar@israuniversity.edu.pk', '+92 22 2030181 Ext. 253', 'EE-021', 'Electrical Engineering', '2026-06-10 05:36:30', '2026-06-10 05:36:30', NULL);
INSERT INTO `teachers` (`id`, `name`, `designation`, `photo`, `sort_order`, `qualifications`, `description`, `current_positions`, `education`, `experience`, `publications`, `awards`, `email`, `contact_number`, `code`, `department`, `created_at`, `updated_at`, `category`) VALUES (22, 'Dr. Saad Baloch', 'Associate Professor', 'teachers/dr_saad_baloch.jpeg', 3, 'Ph.D, ME, BE', '<p class="MsoNormal" style="text-align: justify; mso-pagination: none; tab-stops: .25in; mso-layout-grid-align: none; text-autospace: none;"><span style="font-family: Times New Roman, serif;"><span style="font-size: 16px;">Dr. Saad Baloch is serving as an Associate Professor in the Department of Electrical Engineering at Isra University. He holds a PhD in Electrical Engineering and has extensive academic, research, and professional experience in the fields of power electronics, renewable energy systems, electrical machines, and engineering education. </span></span><span style="font-family: Times New Roman, serif;"><span style="font-size: 16px;">His research interests primarily include DC-DC converters, Single Active Bridge (SAB) converters, sliding mode control, intelligent control techniques for power converters, renewable energy integration, and advanced power electronic systems. He has actively contributed to academic research through publications, technical reviews, and participation in national and international conferences and seminars.</span></span></p>\r\n<p class="MsoNormal" style="text-align: justify; mso-pagination: none; tab-stops: .25in; mso-layout-grid-align: none; text-autospace: none;"><span style="font-family: Times New Roman, serif;"><span style="font-size: 16px;">Dr. Saad Baloch has been actively involved in Outcome-Based Education (OBE) implementation, accreditation activities, curriculum development, Continuous Professional Development (CPD) initiatives, and engineering education quality enhancement. He has participated in and coordinated various workshops and seminars related to OBE systems, accreditation processes, MATLAB/Simulink applications, sustainable energy systems, and emerging engineering technologies.</span></span></p>\r\n<p class="MsoNormal" style="text-align: justify; mso-pagination: none; tab-stops: .25in; mso-layout-grid-align: none; text-autospace: none;"><span style="font-family: Times New Roman, serif;"><span style="font-size: 16px;">He has supervised undergraduate engineering projects and guided students in research, innovation, and technical development activities. His academic focus emphasizes practical learning, industry linkage, research-oriented teaching methodologies, and professional ethics in engineering education.</span></span></p>\r\n<p class="MsoNormal" style="text-align: justify; mso-pagination: none; tab-stops: .25in; mso-layout-grid-align: none; text-autospace: none;"><span style="font-family: Times New Roman, serif;"><span style="font-size: 16px;">Dr. Saad Baloch is also associated with several academic and professional development initiatives aimed at strengthening engineering education standards and promoting technical capacity building among students and faculty members.</span></span></p>\r\n<p class="MsoNormal" style="text-align: justify; mso-pagination: none; tab-stops: .25in; mso-layout-grid-align: none; text-autospace: none;"><span style="font-family: Times New Roman, serif;"><span style="font-size: 16px;">Dr. Saad Baloch has published several research papers in reputed national and international journals and conference proceedings in the areas of power electronics, renewable energy systems, intelligent control techniques, and electrical engineering applications. His research work mainly focuses on DC-DC converters, Single Active Bridge (SAB) converters, sliding mode control, fuzzy logic and AI-based control techniques, renewable energy integration, switched reluctance motor drives, smart energy systems, and advanced power electronic converter topologies.&nbsp;</span></span></p>\r\n<p class="MsoNormal" style="text-align: justify; mso-pagination: none; tab-stops: .25in; mso-layout-grid-align: none; text-autospace: none;"><span style="font-family: Times New Roman, serif;"><span style="font-size: 16px;">He has also contributed to activities related to engineering education, Outcome-Based Education (OBE), and accreditation systems. His academic and research contributions continue to support innovation, practical engineering solutions, and quality enhancement in higher education.</span></span></p>', '<table class="MsoNormalTable" style="box-sizing: border-box; border-spacing: 0px; border-collapse: collapse; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial; color: #8b8e94; font-family: Raleway, Arial, sans-serif; font-size: 15px; width: 7.5in; border: none; height: 52px;" border="1" width="7.5in" cellspacing="0" cellpadding="0">\r\n<thead style="box-sizing: border-box;">\r\n<tr style="box-sizing: border-box; height: 26px;">\r\n<td style="box-sizing: border-box; padding: 6pt; width: 213px; border-top: none; border-left: 1pt solid #dddddd; border-bottom: 1.5pt solid #dddddd; border-right: 1pt solid #dddddd; height: 26px;" valign="bottom">\r\n<p class="MsoNormal" style="box-sizing: border-box; margin: 0px 0px 15pt; line-height: normal;"><span style="box-sizing: border-box; font-weight: bold;"><span style="box-sizing: border-box; font-size: 11.5pt; font-family: Arial, sans-serif;">From - To</span></span></p>\r\n</td>\r\n<td style="box-sizing: border-box; padding: 6pt; width: 130px; border-top: none; border-left: none; border-bottom: 1.5pt solid #dddddd; border-right: 1pt solid #dddddd; height: 26px;" valign="bottom">\r\n<p class="MsoNormal" style="box-sizing: border-box; margin: 0px 0px 15pt; line-height: normal;"><span style="box-sizing: border-box; font-weight: bold;"><span style="box-sizing: border-box; font-size: 11.5